class Solution {
   public:
      bool merge(vector<array<int, 2>>& intervals, array<int, 2>& newInterval) {
         sort(intervals.begin(), intervals.end());
         vector<array<int, 2>> result;
         result.push_back(intervals[0]);
         for (int i = 1; i < intervals.size(); i++) {
            if (result.back()[1] >= intervals[i][0]) {
               result.back()[1] = max(result.back()[1], intervals[i][1]);
            } else {
               result.push_back(intervals[i]);
            }
         }
         bool inserted = false;
         for (int j = 0; j < result.size(); j++) {
            if (result[j][0] <= newInterval[0] && newInterval[1] <= result[j][1]) {
               return true;
            } else if (result[j][0] <= newInterval[1] && newInterval[0] <= result[j][1]) {
               result[j] = {result[j][0], max(result[j][1], newInterval[1])};
               inserted = true;
               break;
            }
         }
         if (!inserted) {
            result.push_back(newInterval);
         }
         return true;
      }
   };

